+// reloadStatusStore keeps the last good configuration in memory and makes the
+// operator-facing outcome of reload attempts survive restarts.
+type reloadStatusStore struct {
+	mu       sync.RWMutex
+	path     string
+	status   api_v1.ReloadStatus
+	lastGood *config.Config
+}
+
+func newReloadStatusStore(storagePath string) *reloadStatusStore {
+	s := &reloadStatusStore{
+		path: filepath.Join(storagePath, reloadStatusFilename),
+		status: emptyReloadStatus(),
+	}
+
+	contents, err := os.ReadFile(s.path)
+	if err != nil {
+		return s
+	}
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(contents, &status); err != nil {
+		return s
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	s.status = status
+	return s
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+}
+
+func (s *reloadStatusStore) setLastGood(cfg *config.Config) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	s.lastGood = cfg
+}
+
+func (s *reloadStatusStore) lastKnownGood() *config.Config {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.lastGood
+}
+
+func (s *reloadStatusStore) snapshot() api_v1.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	status := s.status
+	status.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]float64, len(s.status.ReloaderTimingsMS))
+	for name, timing := range s.status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = timing
+	}
+	return status
+}
+
+func (s *reloadStatusStore) record(status api_v1.ReloadStatus) {
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	s.mu.Lock()
+	s.status = status
+	s.mu.Unlock()
+
+	// Durability is diagnostic only. A storage error must never turn a reload
+	// outcome into a failed configuration reload.
+	contents, err := json.Marshal(status)
+	if err != nil {
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(s.path), 0o755); err != nil {
+		return
+	}
+	tmp := s.path + ".tmp"
+	if err := os.WriteFile(tmp, contents, 0o644); err != nil {
+		return
+	}
+	_ = os.Rename(tmp, s.path)
+}
